<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  *, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #1a1d23;
    color: #e0e0e0;
    min-height: 100vh;
    padding: 2rem;
  }

  h1 {
    text-align: center;
    font-size: 1.8rem;
    font-weight: 600;
    margin-bottom: 2rem;
    color: #ffffff;
    letter-spacing: -0.5px;
  }

  .board {
    display: flex;
    gap: 1.5rem;
    max-width: 1200px;
    margin: 0 auto;
    align-items: flex-start;
  }

  .column {
    flex: 1;
    background: #242830;
    border-radius: 12px;
    padding: 1rem;
    min-height: 400px;
    display: flex;
    flex-direction: column;
    box-shadow: 0 4px 24px rgba(0, 0, 0, 0.3);
    transition: background-color 0.2s ease;
  }

  .column.drag-over {
    background: #2a3040;
  }

  .column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    margin-bottom: 1rem;
    border-bottom: 2px solid #333842;
  }

  .column-header h2 {
    font-size: 1rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .count {
    background: #3a3f4b;
    color: #aaa;
    font-size: 0.75rem;
    font-weight: 600;
    padding: 0.2rem 0.6rem;
    border-radius: 999px;
    min-width: 1.5rem;
    text-align: center;
  }

  .card-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    min-height: 60px;
  }

  .card {
    background: #2e3340;
    border-radius: 8px;
    padding: 0.85rem 1rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.75rem;
    cursor: grab;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
    transition: transform 0.15s ease, box-shadow 0.15s ease, opacity 0.15s ease;
    user-select: none;
  }

  .card:hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
  }

  .card.dragging {
    opacity: 0.5;
    transform: rotate(2deg);
  }

  .card-title {
    flex: 1;
    font-size: 0.9rem;
    line-height: 1.4;
    word-break: break-word;
  }

  .card-del {
    background: none;
    border: none;
    color: #888;
    cursor: pointer;
    font-size: 1.1rem;
    padding: 0.2rem 0.4rem;
    border-radius: 4px;
    line-height: 1;
    transition: color 0.15s ease, background-color 0.15s ease;
    flex-shrink: 0;
  }

  .card-del:hover {
    color: #ff6b6b;
    background-color: rgba(255, 107, 107, 0.1);
  }

  .add-bar {
    max-width: 1200px;
    margin: 0 auto 1.5rem;
    display: flex;
    gap: 0.75rem;
  }

  #new-card {
    flex: 1;
    padding: 0.75rem 1rem;
    border-radius: 8px;
    border: 2px solid #333842;
    background: #242830;
    color: #e0e0e0;
    font-size: 0.9rem;
    outline: none;
    transition: border-color 0.2s ease;
  }

  #new-card:focus {
    border-color: #5b7fff;
  }

  #new-card::placeholder {
    color: #666;
  }

  #add-card {
    padding: 0.75rem 1.5rem;
    border-radius: 8px;
    border: none;
    background: #4a6cf7;
    color: #fff;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.2s ease, transform 0.1s ease;
  }

  #add-card:hover {
    background: #3a5ce7;
  }

  #add-card:active {
    transform: scale(0.97);
  }

  .col-todo .column-header h2 { color: #6cb4ee; }
  .col-doing .column-header h2 { color: #f5a623; }
  .col-done .column-header h2 { color: #4cd964; }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="add-bar">
  <input type="text" id="new-card" placeholder="What needs to be done?" autocomplete="off">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column col-todo" id="col-todo">
    <div class="column-header">
      <h2>To Do</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>

  <div class="column col-doing" id="col-doing">
    <div class="column-header">
      <h2>Doing</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>

  <div class="column col-done" id="col-done">
    <div class="column-header">
      <h2>Done</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
</div>

<script>
(function() {
  const STORAGE_KEY = 'kanban-board-state';
  const columns = ['col-todo', 'col-doing', 'col-done'];

  function loadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch(e) {}
    return [];
  }

  function saveState(cards) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
  }

  function generateId() {
    return 'card-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
  }

  function createCardElement(title, id) {
    const card = document.createElement('div');
    card.className = 'card';
    card.setAttribute('draggable', 'true');
    card.dataset.id = id;

    const titleEl = document.createElement('span');
    titleEl.className = 'card-title';
    titleEl.textContent = title;

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.setAttribute('aria-label', 'Delete card');
    delBtn.innerHTML = '&#x2715;';

    card.appendChild(titleEl);
    card.appendChild(delBtn);

    delBtn.addEventListener('click', function() {
      deleteCard(id);
    });

    return card;
  }

  function addCardToColumn(columnId, title) {
    const id = generateId();
    const container = document.querySelector('#' + columnId + ' .card-container');
    const cardEl = createCardElement(title, id);
    container.appendChild(cardEl);
    attachDragHandlers(cardEl);
    updateCounts();
    persistState();
    return id;
  }

  function deleteCard(id) {
    const el = document.querySelector('.card[data-id="' + id + '"]');
    if (el) el.remove();
    updateCounts();
    persistState();
  }

  function moveCard(cardEl, targetColumnId) {
    const container = document.querySelector('#' + targetColumnId + ' .card-container');
    container.appendChild(cardEl);
    updateCounts();
    persistState();
  }

  function updateCounts() {
    columns.forEach(function(colId) {
      const col = document.getElementById(colId);
      const countEl = col.querySelector('.count');
      const numCards = col.querySelectorAll('.card').length;
      countEl.textContent = String(numCards);
    });
  }

  function persistState() {
    const cards = [];
    columns.forEach(function(colId) {
      const container = document.querySelector('#' + colId + ' .card-container');
      container.querySelectorAll('.card').forEach(function(cardEl) {
        const titleEl = cardEl.querySelector('.card-title');
        if (titleEl) {
          cards.push({ id: cardEl.dataset.id, column: colId, title: titleEl.textContent });
        }
      });
    });
    saveState(cards);
  }

  function attachDragHandlers(cardEl) {
    cardEl.addEventListener('dragstart', function(e) {
      cardEl.classList.add('dragging');
      e.dataTransfer.setData('text/plain', cardEl.dataset.id);
      e.dataTransfer.effectAllowed = 'move';
    });

    cardEl.addEventListener('dragend', function() {
      cardEl.classList.remove('dragging');
      columns.forEach(function(colId) {
        document.getElementById(colId).classList.remove('drag-over');
      });
    });
  }

  function initDragAndDrop() {
    columns.forEach(function(colId) {
      const col = document.getElementById(colId);
      const container = col.querySelector('.card-container');

      col.addEventListener('dragover', function(e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        col.classList.add('drag-over');
      });

      col.addEventListener('dragleave', function(e) {
        if (!col.contains(e.relatedTarget)) {
          col.classList.remove('drag-over');
        }
      });

      col.addEventListener('drop', function(e) {
        e.preventDefault();
        col.classList.remove('drag-over');
        const cardId = e.dataTransfer.getData('text/plain');
        if (!cardId) return;
        const cardEl = document.querySelector('.card[data-id="' + cardId + '"]');
        if (cardEl && cardEl.parentElement !== container) {
          moveCard(cardEl, colId);
        }
      });
    });
  }

  function renderBoard() {
    const cards = loadState();
    columns.forEach(function(colId) {
      const container = document.querySelector('#' + colId + ' .card-container');
      container.innerHTML = '';
    });
    cards.forEach(function(cardData) {
      const cardEl = createCardElement(cardData.title, cardData.id);
      attachDragHandlers(cardEl);
      const container = document.querySelector('#' + cardData.column + ' .card-container');
      if (container) {
        container.appendChild(cardEl);
      }
    });
    updateCounts();
  }

  function handleAddCard() {
    const input = document.getElementById('new-card');
    const text = input.value.trim();
    if (!text) return;
    addCardToColumn('col-todo', text);
    input.value = '';
    input.focus();
  }

  document.getElementById('add-card').addEventListener('click', handleAddCard);

  document.getElementById('new-card').addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      handleAddCard();
    }
  });

  initDragAndDrop();
  renderBoard();
})();
</script>

</body>
</html>
